#[test]
fn test_qft_vs_julia() {
    let Some(data) = load_qft() else {
        eprintln!("Skipping: qft.json not found");
        return;
    };
    for nq in 4..=25 {
        let key = nq.to_string();
        if let Some(expected_state) = data.get(&key) {
            let expected = interleaved_to_complex(expected_state);
            let mut init = vec![Complex64::new(0.0, 0.0); 1 << nq];
            init[1] = Complex64::new(1.0, 0.0);
            let reg = ArrayReg::from_vec(nq, init);
            let circuit = yao_rs::easybuild::qft_circuit(nq);
            let result = apply(&circuit, &reg);
            assert_state_close(result.state_vec(), &expected, &format!("QFT/{nq}q"));
        }
    }
}

#[test]
fn test_qft_analytical() {
    use std::f64::consts::PI;

    for nq in 4..=16 {
        let dim = 1usize << nq;
        let mut init = vec![Complex64::new(0.0, 0.0); dim];
        init[1] = Complex64::new(1.0, 0.0);
        let reg = ArrayReg::from_vec(nq, init);
        let circuit = yao_rs::easybuild::qft_circuit(nq);
        let result = apply(&circuit, &reg);

        let amp = 1.0 / (dim as f64).sqrt();
        for idx in 0..dim {
            let reversed = idx.reverse_bits() >> (usize::BITS as usize - nq);
            let phase = 2.0 * PI * (reversed as f64) / (dim as f64);
            let expected = Complex64::new(amp * phase.cos(), amp * phase.sin());
            let diff = (result.state_vec()[idx] - expected).norm();
            assert!(
                diff < ATOL_STATE,
                "QFT analytical/{nq}q[{idx}]: diff={diff}"
            );
        }
    }
}
